// // This module is designed to decrement a 4-bit counter synchronously when enabled.
module sync_counter_4bit(
    input clk,
    input rst_n,
    input enable,
    output reg [3:0] count
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        count <= 4'd0;
    else if (enable)
        count <= count + 1;
end

endmodule
